#include<bits/stdc++.h>using namespace std;int q,n,ans=0;string s,t;int f(int b[]){	for(int i=0;i<3;i++){		if(!b[i]){			return i;		}	}}int main(){	cin>>q;	while(q--){		cin>>n>>s>>t;		string s1="",s2="";		s1=s1+s[0];s2=s2+t[0];		int b[20];		b[s[0]-'0']++;b[t[0]-'0']++;		int mex=f(b);		for(int i=1;i<s.size();i++){			if(mex==0){				s1=s1+s[i];s2=s2+t[i];				b[s[i]-'0']++;b[t[i]-'0']++;				mex=f(b);			}else if(mex==2){				ans+=mex;				s1="";s2="";				memset(b,0,sizeof b);				s1=s1+s[i];s2=s2+t[i];				b[s[i]-'0']++;b[t[i]-'0']++;				mex=f(b);			}else{				if(s[i]=='0'&&t[i]=='0' || s[i]!=t[i]){					ans+=mex;					s1="";s2="";					memset(b,0,sizeof b);					s1=s1+s[i];s2=s2+t[i];					b[s[i]-'0']++;b[t[i]-'0']++;					mex=f(b);				}else{					s1=s1+s[i];s2=s2+t[i];					b[s[i]-'0']++;b[t[i]-'0']++;					mex=f(b);				}			}		}		ans+=mex;		cout<<ans<<endl;		ans=0;	}	return 0;}